        if (isalnum(str[i])) {
            length++;
        }
    }

    // Initialize pointers
    front = 0;
    back = length - 1;

    // Check for palindrome
    while (front < back) {
        if (!isalnum(str[front])) {
            front++;
        } else if (!isalnum(str[back])) {
            back--;
        } else if (tolower(str[front]) != tolower(str[back])) {
            printf("It is not a palindrome.\n");
            return 0;
        } else {
            front++;
            back--;
        }
    }

    printf("It is a palindrome!\n");
    return 0;
}
