class UniqueIDGenerator {
    private static readonly SEED = Date.now(); // A seed for randomness, unique each millisecond
    private static readonly CHARACTERS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    private static readonly ID_LENGTH = 16; // Length of the generated ID

    private static _instance: UniqueIDGenerator;

    /**
     * Generates a random unique ID.
     */
    public static getInstance(): UniqueIDGenerator {
        if (!this._instance) {
            this._instance = new UniqueIDGenerator();
        }
        return this._instance;
    }

    private constructor() {}

    /**
     * Creates a unique ID using a combination of characters.
     */
    public generateID(): string {
        let id = '';
        const maxPos = this.CHARACTERS.length - 1;

        for (let i = 0; i < this.ID_LENGTH; i++) {
            id += this.CHARACTERS.charAt(Math.floor(Math.random() * maxPos));
        }

        return id;
    }
}
```

