<?php
function isPerfectSquare($number) {
    // Validate the input, ensuring it's a positive integer
    if (!is_numeric($number) || $number < 0) {
        return "Please enter a positive integer.";
    }

    // Calculate the square root and round it
    $sqrt = sqrt($number);

    // Check if the rounded square root squared equals the original number
    if (floor($sqrt) == $sqrt) {
        return "The number {$number} is a perfect square!";
    } else {
        return "The number {$number} is not a perfect square.";
    }
}

